export interface ScheduledTime {
  hours: number;
  minutes: number;
}

export interface Quote {
  id: number;
  text: string;
}

export enum AppState {
  LOADING = 'LOADING',
  IDLE = 'IDLE',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { HEALING_QUOTES } from '../constants';

class NotificationService {
  async requestPermission(): Promise<boolean> {
    if (!('Notification' in window)) {
      console.warn('이 브라우저는 알림을 지원하지 않습니다.');
      return false;
    }

    if (Notification.permission === 'granted') {
      return true;
    }

    const permission = await Notification.requestPermission();
    return permission === 'granted';
  }

  showRandomQuote(): void {
    if (Notification.permission !== 'granted') {
      return;
    }

    const randomIndex = Math.floor(Math.random() * HEALING_QUOTES.length);
    const quote = HEALING_QUOTES[randomIndex];

    new Notification('힐링 모먼트', {
      body: quote.text,
      icon: 'https://cdn-icons-png.flaticon.com/512/3209/3209931.png'
    });
  }

  getPermissionStatus(): NotificationPermission {
    return Notification.permission;
  }
}

export const notificationService = new NotificationService();

