import React, { useState, useEffect, useCallback } from 'react';
import { ScheduledTime, AppState } from './types';
import { STORAGE_KEY, HEALING_QUOTES } from './constants';
import { notificationService } from './services/notificationService';
import TimePicker from './components/TimePicker';

const App: React.FC = () => {
  const [scheduledTime, setScheduledTime] = useState<ScheduledTime>({ hours: 9, minutes: 0 });
  const [permissionGranted, setPermissionGranted] = useState<boolean>(false);
  const [status, setStatus] = useState<AppState>(AppState.IDLE);
  const [lastCheck, setLastCheck] = useState<string>('');

  // Load initial settings
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setScheduledTime(JSON.parse(saved));
    }

    // Check permission on mount
    const currentPermission = notificationService.getPermissionStatus();
    setPermissionGranted(currentPermission === 'granted');
  }, []);

  // Background monitor simulation
  // Note: Standard web apps can't reliably trigger notifications while closed without a service worker.
  // This simulation runs while the app is open.
  useEffect(() => {
    const checkInterval = setInterval(() => {
      const now = new Date();
      const currentH = now.getHours();
      const currentM = now.getMinutes();
      const timeStr = `${currentH}:${currentM}`;

      if (currentH === scheduledTime.hours && currentM === scheduledTime.minutes && lastCheck !== timeStr) {
        notificationService.showRandomQuote();
        setLastCheck(timeStr);
      }
    }, 10000); // Check every 10 seconds

    return () => clearInterval(checkInterval);
  }, [scheduledTime, lastCheck]);

  const handleRequestPermission = async () => {
    const granted = await notificationService.requestPermission();
    setPermissionGranted(granted);
    if (!granted) {
      alert('알림 권한이 거부되었습니다. 설정에서 알림을 허용해주세요.');
    }
  };

  const saveTime = (time: ScheduledTime) => {
    setScheduledTime(time);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(time));
    setStatus(AppState.SUCCESS);
    setTimeout(() => setStatus(AppState.IDLE), 3000);
  };

  const handleManualTest = () => {
    if (!permissionGranted) {
      handleRequestPermission();
    } else {
      notificationService.showRandomQuote();
    }
  };

  return (
    <div className="min-h-screen pastel-gradient flex flex-col items-center px-4 py-12 text-gray-800">
      {/* Header Section */}
      <div className="text-center mb-12">
        <div className="inline-block p-4 bg-white rounded-full shadow-md mb-4 animate-bounce">
          <i className="fa-solid fa-heart text-pink-400 text-3xl"></i>
        </div>
        <h1 className="text-4xl font-extrabold text-pink-600 mb-2">힐링 모먼트</h1>
        <p className="text-pink-400 font-medium">따뜻한 응원이 필요한 순간, 당신에게 찾아갈게요.</p>
      </div>

      {/* Main Content */}
      <div className="w-full flex flex-col items-center space-y-8 max-w-lg">
        {/* Permission Banner */}
        {!permissionGranted && (
          <div className="w-full bg-yellow-100 border-l-4 border-yellow-400 p-4 rounded-lg flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3">
              <i className="fa-solid fa-circle-exclamation text-yellow-600"></i>
              <p className="text-sm text-yellow-700">알림 권한이 필요합니다.</p>
            </div>
            <button
              onClick={handleRequestPermission}
              className="bg-yellow-500 text-white text-xs font-bold px-3 py-1 rounded-full hover:bg-yellow-600"
            >
              허용하기
            </button>
          </div>
        )}

        {/* Current Status Display */}
        <div className="text-center">
          <p className="text-gray-400 text-sm uppercase tracking-widest mb-1">현재 설정된 시간</p>
          <div className="text-6xl font-black text-pink-500 drop-shadow-sm">
            {scheduledTime.hours.toString().padStart(2, '0')}
            <span className="animate-pulse">:</span>
            {scheduledTime.minutes.toString().padStart(2, '0')}
          </div>
        </div>

        {/* Action Components */}
        <TimePicker initialTime={scheduledTime} onSave={saveTime} />

        {/* Status Toast */}
        {status === AppState.SUCCESS && (
          <div className="fixed bottom-10 bg-green-500 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-bounce">
            <i className="fa-solid fa-check-circle"></i>
            설정이 저장되었습니다!
          </div>
        )}

        {/* Manual Test Button */}
        <button
          onClick={handleManualTest}
          className="group flex items-center gap-3 text-pink-400 hover:text-pink-600 font-semibold transition-colors bg-white/40 px-6 py-3 rounded-2xl hover:bg-white/60"
        >
          <i className="fa-solid fa-wand-magic-sparkles group-hover:rotate-12 transition-transform"></i>
          지금 바로 응원 받기 (테스트)
        </button>

        {/* Info Card */}
        <div className="bg-white/40 p-6 rounded-3xl border border-white/60 text-sm text-gray-500 leading-relaxed shadow-sm">
          <h3 className="font-bold text-gray-600 mb-2 flex items-center gap-2">
            <i className="fa-solid fa-circle-info"></i>
            알아두세요
          </h3>
          <ul className="list-disc list-inside space-y-1">
            <li>이 앱은 20여 개의 따뜻한 격려 문구를 담고 있습니다.</li>
            <li>브라우저 탭이 열려 있을 때 설정한 시간에 알림이 도착합니다.</li>
            <li>실제 서비스에서는 백그라운드 작업(Service Worker)이 필요합니다.</li>
          </ul>
        </div>
      </div>

      {/* Footer */}
      <footer className="mt-auto pt-12 pb-4 text-pink-300 text-xs">
        &copy; 2024 Healing Moments. Made with Love.
      </footer>
    </div>
  );
};

export default App;

